"use client";

import { type TocProps, Toc as TocRoot } from "./toc";
import { TocItem, type TocItemProps, type TocItemRenderProps, tocItemVariants } from "./toc-item";
import { TocList, type TocListProps } from "./toc-list";

/** Root aside wrapper and optional heading label. */
const Toc = Object.assign(TocRoot, {
  List: TocList,
  Item: TocItem,
});

export { Toc, type TocProps };
export { TocList, type TocListProps };
export { TocItem, type TocItemProps, type TocItemRenderProps, tocItemVariants };

"use client";

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

/** Props for toc. */
export interface TocProps extends Omit<ComponentPropsWithRef<"nav">, "title"> {
  /** Heading text and accessible label for the nav landmark. */
  title?: string;
  /** Heading level used for the title. */
  as?: "h2" | "h3" | "h4";
}

/** Root aside wrapper and optional heading label. */
export function Toc({
  title = "On this page",
  as: Heading = "h2",
  className,
  children,
  ref,
  ...props
}: TocProps) {
  return (
    <nav
      ref={ref}
      data-slot="toc"
      aria-label={title}
      className={cn("w-56 shrink-0 py-8 pr-4", className)}
      {...props}
    >
      <Heading className="mb-3 text-2xs font-bold uppercase tracking-wider text-muted-foreground font-mono">
        {title}
      </Heading>
      {children}
    </nav>
  );
}

"use client";

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

/** Props for toc list. */
export type TocListProps = ComponentPropsWithRef<"ul">;

/** List container for TOC items. */
export function TocList({ className, children, ref, ...props }: TocListProps) {
  return (
    // biome-ignore lint/a11y/useSemanticElements: this already is a <ul>; the explicit role="list" below restores list semantics that Tailwind preflight strips, and Biome should not suggest swapping the element.
    <ul
      ref={ref}
      data-slot="toc-list"
      // biome-ignore lint/a11y/noRedundantRoles: Tailwind preflight sets list-style:none on <ul>, which drops list semantics in Safari/VoiceOver; role="list" restores them.
      role="list"
      className={cn("border-l border-border flex flex-col gap-1.5", className)}
      {...props}
    >
      {children}
    </ul>
  );
}

"use client";

import { cva } from "class-variance-authority";
import type {
  AnchorHTMLAttributes,
  ComponentPropsWithRef,
  CSSProperties,
  ReactNode,
  Ref,
} from "react";
import { cn } from "@/lib/utils";

const INDENT_BASE_PX = 12;
const INDENT_PER_LEVEL_PX = 12;

/** Class variants for toc item. */
export const tocItemVariants = cva(
  "block py-1 text-xs font-mono transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring",
  {
    variants: {
      active: {
        true: "text-primary font-bold",
        false: "text-muted-foreground hover:text-foreground",
      },
    },
    defaultVariants: {
      active: false,
    },
  },
);

/** Props for toc item render. */
export type TocItemRenderProps = AnchorHTMLAttributes<HTMLAnchorElement> & {
  ref: Ref<HTMLAnchorElement>;
  className: string;
  style: CSSProperties;
  "data-slot": "toc-item";
  "data-selected"?: true;
};

/** Props for toc item. */
export interface TocItemProps extends Omit<ComponentPropsWithRef<"a">, "children"> {
  /** Link label, or a render function for framework Link integration. */
  children: ReactNode | ((props: TocItemRenderProps) => ReactNode);
  /** Marks the link as the current location. Adds aria-current="location" and data-selected. */
  active?: boolean;
  /** Heading depth (2 = h2). Drives left padding; values below 2 are treated as 2. */
  depth?: number;
}

/** Individual TOC entry with depth/active styling. */
export function TocItem({
  children,
  depth = 2,
  active,
  className,
  style,
  ref,
  ...props
}: TocItemProps) {
  const indent = Math.max(0, depth - 2) * INDENT_PER_LEVEL_PX + INDENT_BASE_PX;

  const renderProps: TocItemRenderProps = {
    ref: ref ?? null,
    "aria-current": active ? "location" : undefined,
    "data-slot": "toc-item",
    "data-selected": active || undefined,
    className: cn(tocItemVariants({ active }), className),
    style: { paddingLeft: `${indent}px`, ...style },
    ...props,
  };

  if (typeof children === "function") return <li>{children(renderProps)}</li>;

  return (
    <li>
      <a {...renderProps}>{children}</a>
    </li>
  );
}
